#include<bits/stdc++.h>
using namespace std;bool a[505][505][505];int x,y,z;
int main(void){cin>>x>>y>>z;for(int i=1;i<=z;i++){for(int j=1;j<=x;j++){for(int k=1;k<=y;k++){cin>>a[i][j][k];}}}
	for(int i=z;i>=1;i--){for(int j=1;j<=x;j++){bool flag=false;for(int k=1;k<=y;k++){if(a[i][j][k]==true){flag=true;break;}}cout<<flag<<' ';}cout<<"\n";}
	for(int i=z;i>=1;i--){for(int j=y;j>=1;j--){bool flag=false;for(int k=1;k<=x;k++){if(a[i][k][j]==true){flag=true;break;}}cout<<flag<<' ';}cout<<"\n";}
	for(int i=y;i>=1;i--){for(int j=1;j<=x;j++){bool flag=false;for(int k=1;k<=z;k++){if(a[k][j][i]==true){flag=true;break;}}cout<<flag<<' ';}cout<<"\n";}
	return false;
}
